pub struct FindManySelectQuery<'a> {
    client: &'a DatabaseClient,
    r#where: filter::ProfileWhereInput,
    order_by: Vec<order::ProfileOrderByInput>,
    skip: Option<i64>,
    take: Option<i64>,
    select: ProfileSelect,
}
impl<'a> FindManySelectQuery<'a> {
    pub fn order_by(mut self, order: order::ProfileOrderByInput) -> Self {
        self.order_by.push(order);
        self
    }
    pub fn skip(mut self, n: i64) -> Self {
        self.skip = Some(n);
        self
    }
    pub fn take(mut self, n: i64) -> Self {
        self.take = Some(n);
        self
    }
    pub async fn exec(self) -> Result<Vec<ProfilePartial>, FerriormError> {
        let cols = build_select_columns(&self.select);
        let base_sql = format!("SELECT {} FROM \"profiles\" WHERE 1=1", cols);
        match self.client {
            DatabaseClient::Postgres(_) => {
                let qb = build_select_query::<
                    sqlx::Postgres,
                >(&base_sql, &self.r#where, &self.order_by, self.take, self.skip);
                self.client.fetch_all_pg(qb).await
            }
            DatabaseClient::Sqlite(_) => {
                let qb = build_select_query::<
                    sqlx::Sqlite,
                >(&base_sql, &self.r#where, &self.order_by, self.take, self.skip);
                self.client.fetch_all_sqlite(qb).await
            }
        }
    }
}
