#[derive(Debug, Clone, Default)]
pub struct ProfileInclude {
    pub user: bool,
}
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProfileWithRelations {
    #[serde(flatten)]
    pub data: Profile,
    pub user: Option<super::user::User>,
}
impl Profile {
    /// Load relations for a batch of records.
    pub(crate) async fn load_relations(
        records: Vec<Profile>,
        include: &ProfileInclude,
        client: &DatabaseClient,
    ) -> Result<Vec<ProfileWithRelations>, FerriormError> {
        let mut user_map: std::collections::HashMap<String, super::user::User> = std::collections::HashMap::new();
        if include.user {
            let ids: Vec<String> = records.iter().map(|r| r.user_id.clone()).collect();
            if !ids.is_empty() {
                macro_rules! build_in_query {
                    ($db:ty) => {
                        { let mut qb = sqlx::QueryBuilder:: < $db >
                        ::new("SELECT * FROM \"users\" WHERE \"id\" IN ("); let mut sep =
                        qb.separated(", "); for id in & ids { sep.push_bind(id.clone());
                        } qb.push(")"); qb }
                    };
                }
                match client {
                    DatabaseClient::Postgres(pool) => {
                        let mut qb = build_in_query!(sqlx::Postgres);
                        let related_rows: Vec<super::user::User> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        for row in related_rows {
                            user_map.insert(row.id.clone(), row);
                        }
                    }
                    DatabaseClient::Sqlite(pool) => {
                        let mut qb = build_in_query!(sqlx::Sqlite);
                        let related_rows: Vec<super::user::User> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        for row in related_rows {
                            user_map.insert(row.id.clone(), row);
                        }
                    }
                }
            }
        }
        let mut results = Vec::with_capacity(records.len());
        for r in records {
            results
                .push(ProfileWithRelations {
                    user: if include.user {
                        user_map.remove(&r.user_id).map(Some).unwrap_or(None)
                    } else {
                        None
                    },
                    data: r,
                });
        }
        Ok(results)
    }
}
impl<'a> FindManyQuery<'a> {
    pub fn include(self, include: ProfileInclude) -> FindManyWithIncludeQuery<'a> {
        FindManyWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindManyWithIncludeQuery<'a> {
    inner: FindManyQuery<'a>,
    include: ProfileInclude,
}
impl<'a> FindManyWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Vec<ProfileWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let records = FindManyQuery {
            client,
            r#where: self.inner.r#where,
            order_by: self.inner.order_by,
            skip: self.inner.skip,
            take: self.inner.take,
        }
            .exec()
            .await?;
        Profile::load_relations(records, &include, client).await
    }
}
impl<'a> FindUniqueQuery<'a> {
    pub fn include(self, include: ProfileInclude) -> FindUniqueWithIncludeQuery<'a> {
        FindUniqueWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindUniqueWithIncludeQuery<'a> {
    inner: FindUniqueQuery<'a>,
    include: ProfileInclude,
}
impl<'a> FindUniqueWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Option<ProfileWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let record = FindUniqueQuery {
            client,
            r#where: self.inner.r#where,
        }
            .exec()
            .await?;
        match record {
            Some(r) => {
                let mut results = Profile::load_relations(vec![r], &include, client)
                    .await?;
                Ok(results.pop())
            }
            None => Ok(None),
        }
    }
}
